import{_ as n,o as r,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Konto erstellen","description":"","frontmatter":{},"headers":[],"relativePath":"de/getting-started/create-account.md","filePath":"de/getting-started/create-account.md"}'),a={name:"de/getting-started/create-account.md"};function s(l,e,o,h,d,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="konto-erstellen" tabindex="-1">Konto erstellen <a class="header-anchor" href="#konto-erstellen" aria-label="Permalink to &quot;Konto erstellen&quot;">​</a></h1><p>Der Einstieg in MyCompanyDesk dauert nur wenige Minuten.</p><h2 id="registrieren" tabindex="-1">Registrieren <a class="header-anchor" href="#registrieren" aria-label="Permalink to &quot;Registrieren&quot;">​</a></h2><ol><li>Gehen Sie zu <a href="https://app.mycompanydesk.com" target="_blank" rel="noreferrer">app.mycompanydesk.com</a> und klicken Sie auf <strong>Registrieren</strong></li><li>Wählen Sie eine der folgenden Methoden: <ul><li><strong>E-Mail und Passwort</strong> — Geben Sie Ihren Namen, Ihre E-Mail-Adresse und ein sicheres Passwort ein</li><li><strong>Google</strong> — Melden Sie sich mit Ihrem Google-Konto an</li><li><strong>Microsoft/Outlook</strong> — Melden Sie sich mit Ihrem Microsoft-Konto an</li></ul></li><li>Wenn Sie sich per E-Mail registriert haben, prüfen Sie Ihren Posteingang auf eine <strong>Bestätigungs-E-Mail</strong> und klicken Sie auf den Link, um Ihr Konto zu verifizieren</li></ol><h2 id="arbeitsbereich-erstellen-oder-beitreten" tabindex="-1">Arbeitsbereich erstellen oder beitreten <a class="header-anchor" href="#arbeitsbereich-erstellen-oder-beitreten" aria-label="Permalink to &quot;Arbeitsbereich erstellen oder beitreten&quot;">​</a></h2><p>Nach der Registrierung haben Sie zwei Möglichkeiten:</p><h3 id="neuen-arbeitsbereich-erstellen" tabindex="-1">Neuen Arbeitsbereich erstellen <a class="header-anchor" href="#neuen-arbeitsbereich-erstellen" aria-label="Permalink to &quot;Neuen Arbeitsbereich erstellen&quot;">​</a></h3><p>Wenn Sie die erste Person aus Ihrem Unternehmen sind, erstellen Sie einen neuen Arbeitsbereich:</p><ol><li>Geben Sie Ihren <strong>Firmennamen</strong> ein</li><li>Wählen Sie Ihre bevorzugte <strong>Sprache</strong></li><li>Klicken Sie auf <strong>Arbeitsbereich erstellen</strong></li></ol><p>Dies erstellt einen neuen Arbeitsbereich, in dem Sie Ihre Unternehmensinformationen, Kunden und Rechnungen hinzufügen können.</p><h3 id="einem-bestehenden-arbeitsbereich-beitreten" tabindex="-1">Einem bestehenden Arbeitsbereich beitreten <a class="header-anchor" href="#einem-bestehenden-arbeitsbereich-beitreten" aria-label="Permalink to &quot;Einem bestehenden Arbeitsbereich beitreten&quot;">​</a></h3><p>Wenn ein Kollege bereits einen Arbeitsbereich eingerichtet hat:</p><ol><li>Bitten Sie ihn, Ihnen eine <strong>Einladung</strong> über Einstellungen &gt; Team zu senden</li><li>Klicken Sie auf den Einladungslink in Ihrer E-Mail</li><li>Nehmen Sie die Einladung an, um dem Arbeitsbereich beizutreten</li></ol><p>Sie können Mitglied mehrerer Arbeitsbereiche sein und über Ihr Kontomenü zwischen ihnen wechseln.</p><h2 id="dashboard-profil-wahlen" tabindex="-1">Dashboard-Profil wählen <a class="header-anchor" href="#dashboard-profil-wahlen" aria-label="Permalink to &quot;Dashboard-Profil wählen&quot;">​</a></h2><p>Bei der ersten Anmeldung sehen Sie die <strong>Onboarding-Karte</strong> auf Ihrem Dashboard. MyCompanyDesk bietet Dashboard-Profile, die auf verschiedene Rollen zugeschnitten sind:</p><ul><li><strong>Inhaber / Geschäftsführer</strong> — Finanzieller Überblick auf hoher Ebene und Cashflow</li><li><strong>Buchhalter / Steuerberater</strong> — USt.-Compliance, Prüfpfade, Periodensperren</li><li><strong>Freiberufler</strong> — Vereinfachte Ansicht mit Fokus auf Rechnungsstellung und Einnahmen</li><li><strong>Projektbasiert</strong> — Projektrentabilität und Zeiterfassung im Fokus</li><li><strong>Debitorenbuchhaltung (Rechnungsstellung)</strong> — Rechnungskennzahlen und Zahlungsverfolgung</li><li><strong>Kreditorenbuchhaltung (Einkauf)</strong> — Ausgabenverfolgung und Lieferantenverwaltung</li><li><strong>USt.-Compliance</strong> — USt.-Berechnungen und Fristen</li><li><strong>Wachstum / Betrieb</strong> — Umsatztrends und Kundenakquise</li></ul><p>Sie können Ihr Dashboard-Profil jederzeit in den Dashboard-Einstellungen ändern.</p><h2 id="onboarding-checkliste-abschließen" tabindex="-1">Onboarding-Checkliste abschließen <a class="header-anchor" href="#onboarding-checkliste-abschließen" aria-label="Permalink to &quot;Onboarding-Checkliste abschließen&quot;">​</a></h2><p>Die Onboarding-Karte führt Sie durch drei wichtige Einrichtungsschritte:</p><ol><li><strong>Unternehmensinformationen einrichten</strong> — Fügen Sie Ihren Firmennamen, Ihre Adresse, USt.-Nummer und Bankdaten hinzu</li><li><strong>Ersten Kunden hinzufügen</strong> — Erstellen Sie einen Kundendatensatz, um mit der Rechnungsstellung zu beginnen</li><li><strong>Erste Rechnung erstellen</strong> — Versenden Sie Ihre erste professionelle Rechnung</li></ol><p>Die Karte verschwindet automatisch, sobald Sie diese Schritte abgeschlossen haben, oder Sie können sie manuell schließen.</p><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Jetzt, da Ihr Konto bereit ist, <a href="/de/getting-started/company-setup">richten Sie Ihre Unternehmensinformationen ein</a>.</p>',24)])])}const b=n(a,[["render",s]]);export{g as __pageData,b as default};
